                            "type": "string",
                            "description": "Output format (json/text)",
                            "enum": ["json", "text"],
                            "default": "json"
                        },
                        "include_globs": {
                            "type": "array",
                            "description": "Custom file glob patterns to include (e.g., ['*.test.js', '*.spec.ts'])",
                            "items": {"type": "string"},
                            "maxItems": 100
                        },
                        "exclude_globs": {
                            "type": "array",
                            "description": "File glob patterns to exclude (e.g., ['node_modules/**', '*.min.js'])",
