                )

            if consistency["extra_in_rewrite"]:
                warnings.append(
                    f"Extra meta-variables in rewrite not defined in pattern: {', '.join(consistency['extra_in_rewrite'])}"
                )

    return {
        "valid": len(errors) == 0,
        "errors": errors,
        "warnings": warnings,
        "suggestions": suggest_meta_variable_fixes(pattern, rewrite)
    }

