def _deduplicate_functions(self, functions: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        """Remove duplicate function detections.

        Args:
            functions: List of detected functions

        Returns:
            List of unique functions
        """
        unique_functions = []
        seen_locations = set()

