def _split_parameters(params_text: str) -> List[str]:
    """Split parameter text by commas, respecting nested structures."""
    if not params_text:
        return []

    parameters = []
    current_param = ""
    nesting_level = 0
    in_string = False
    string_char = None

    for char in params_text:
        if not in_string:
            if char in ['"', "'", '`']:
                in_string = True
                string_char = char
            elif char in ['(', '[', '{']:
                nesting_level += 1
            elif char in [')', ']', '}']:
                nesting_level -= 1
            elif char == ',' and nesting_level == 0:
                parameters.append(current_param)
                current_param = ""
                continue
        else:
            if char == string_char:
                in_string = False
                string_char = None

        current_param += char

    if current_param:
        parameters.append(current_param)

    return parameters

