        """Filter sensitive data from a log record."""
        if hasattr(record, 'msg') and isinstance(record.msg, str):
            record.msg = self.filter_message(record.msg)

        # Filter arguments
        if hasattr(record, 'args') and record.args:
            filtered_args = []
