                    cpu_usage = system_metrics["cpu"]["percent"]
                    if cpu_usage >= self.config.cpu_critical_threshold:
                        system_metrics["cpu"]["status"] = "critical"
                    elif cpu_usage >= self.config.cpu_warning_threshold:
                        system_metrics["cpu"]["status"] = "warning"
                    else:
