                    if memory_usage >= self.config.memory_critical_threshold:
                        system_metrics["memory"]["status"] = "critical"
                    elif memory_usage >= self.config.memory_warning_threshold:
                        system_metrics["memory"]["status"] = "warning"
                    else:
